#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using operator<<
        stream << packet_id;

        // Write username using prefixed adaptor (writes length as uint32_t in little endian)
        stream << hexi::prefixed(username);

        // Write scores count (as uint32_t in little endian) and then elements
        // The operator<< for iterable containers will call write_container internally
        stream << hexi::prefixed(scores);

        // Write metadata using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor to interface with the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the packet's serialise method with the stream
    packet.serialise(stream);

    // Return the buffer containing the serialized data
    return buffer;
}
```

## Explanation:

1. **NetworkPacket::serialise method**:
   - `stream << packet_id`: Directly uses operator<< for uint32_t
   - `stream << hexi::prefixed(username)`: Uses prefixed adaptor for strings (writes length as uint32_t in little endian)
   - `stream << hexi::prefixed(scores)`: Uses prefixed adaptor for vectors (writes count as uint32_t in little endian, then elements via write_container)
   - `stream << hexi::null_terminated(metadata)`: Uses null_terminated adaptor for strings

2. **serialize_packet function**:
   - Creates an empty vector as the buffer
   - Creates a buffer_adaptor to interface with the vector
   - Creates a binary_stream using the buffer_adaptor
   - Calls the packet's serialise method with the stream
   - Returns the buffer containing the serialized data

This implementation follows all the specified requirements and uses the Hexi library functions as documented in the reference materials.

