#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create a buffer_adaptor object for the input buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Calculate total size needed: header size + items vector size
    const size_t total_size = sizeof(header) + items.size() * sizeof(uint32_t);

    // Check if buffer has sufficient free space using the free() function
    if (adaptor.free() < total_size) {
        return false; // Insufficient space
    }

    // Create a binary_stream object using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Use the put function to write the header
    stream.put(header);

    // Use write_container to write the items vector
    stream.write_container(items);

    return true; // Write successful
}
