template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Calculate actual bytes to copy (cannot exceed buffer size)
    size_t bytes_to_copy = bytes_to_peek;
    if (bytes_to_copy > buffer.size()) {
        bytes_to_copy = buffer.size();
    }

    // Create result vector
    std::vector<uint8_t> result(bytes_to_copy);

    // If no data to copy, return empty vector
    if (bytes_to_copy == 0) {
        return result;
    }

    // Start from the first buffer in the linked list
    auto* current_node = buffer.root_.next;
    size_t bytes_copied = 0;

    // Traverse the linked list of buffers
    while (current_node != &buffer.root_ && bytes_copied < bytes_to_copy) {
        // Get the buffer from the node
        const auto* buffer_storage = buffer.buffer_from_node(current_node);

        // Copy data from current buffer
        size_t bytes_available_in_buffer = buffer_storage->size();
        size_t bytes_to_copy_from_buffer = bytes_to_copy - bytes_copied;
        if (bytes_to_copy_from_buffer > bytes_available_in_buffer) {
            bytes_to_copy_from_buffer = bytes_available_in_buffer;
        }

        // Copy data without advancing read pointer
        const auto* source_data = buffer_storage->read_ptr();
        std::copy(source_data, source_data + bytes_to_copy_from_buffer, 
                  result.begin() + bytes_copied);

        bytes_copied += bytes_to_copy_from_buffer;
        current_node = current_node->next;
    }

    return result;
}
