#include <hexi/allocators/block_allocator.h>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator instance with int type and specified element_count
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate free list management through allocation/deallocation cycles
    std::cout << "Block Allocator Free List Management Demonstration\n";
    std::cout << "Element Count: " << element_count << "\n\n";

    // Initial state: all blocks are in free list
    std::cout << "Initial state - all blocks are free\n";

    // Allocate all blocks to exhaust free list
    int* allocated_blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        allocated_blocks[i] = allocator.allocate(i);
        std::cout << "Allocated block " << i << " (address: " << allocated_blocks[i] << ")\n";
    }

    std::cout << "\nAfter allocating all blocks:\n";
    std::cout << "Free list is empty - all blocks are allocated\n";

    // Deallocate blocks to return them to free list
    for (size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(allocated_blocks[i]);
        std::cout << "Deallocated block " << i << " (returned to free list)\n";
    }

    std::cout << "\nAfter deallocating all blocks:\n";
    std::cout << "Free list now contains all " << element_count << " blocks\n";

    // Second allocation cycle to show free list reuse
    std::cout << "\nSecond allocation cycle:\n";
    for (size_t i = 0; i < element_count; ++i) {
        allocated_blocks[i] = allocator.allocate(i * 10);
        std::cout << "Allocated block " << i << " (address: " << allocated_blocks[i] 
                  << ", value: " << *allocated_blocks[i] << ")\n";
    }

    std::cout << "\nFinal state:\n";
    std::cout << "Free list is empty again - all blocks are allocated\n";

    // Deallocate all blocks for proper cleanup
    for (size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(allocated_blocks[i]);
    }

    std::cout << "\nAll blocks deallocated - free list restored\n";
    std::cout << "Demonstration complete!\n";
}
```

**Explanation:**

This implementation demonstrates the internal free list management of `block_allocator` by:

1. **Creating the allocator**: Instantiates `block_allocator<int, element_count>` with the specified element count
2. **Initial state**: Shows that all blocks start in the free list
3. **Allocation cycle**: Uses `allocate()` to remove blocks from the free list, showing how `pop()` is used internally
4. **Deallocation cycle**: Uses `deallocate()` to return blocks to the free list, showing how `push()` is used internally
5. **Free list reuse**: Demonstrates that the free list is circular - after all blocks are deallocated, they can be reused

The output clearly shows the transition of blocks between the free list and allocated state, demonstrating the push/pop behavior that manages the internal linked list structure.

